
"use client";

import { useActionState, useEffect } from 'react'; // Changed from 'react-dom' and 'useFormState'
import { signUpWithEmailPassword } from '@/app/auth/actions';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { useRouter } from 'next/navigation';
import { Loader2 } from 'lucide-react';
import { useFormStatus } from 'react-dom'; // useFormStatus remains in react-dom

const initialState = {
  message: '',
  success: false,
  redirectUrl: '',
};

function SubmitButton() {
  const { pending } = useFormStatus();
  return (
    <Button type="submit" className="w-full font-body" disabled={pending}>
      {pending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
      Sign Up
    </Button>
  );
}

export function SignupForm() {
  const [state, formAction] = useActionState(signUpWithEmailPassword, initialState); // Changed from useFormState
  const { toast } = useToast();
  const router = useRouter();

  useEffect(() => {
    if (state?.message) {
      toast({
        title: state.success ? 'Success' : 'Error',
        description: state.message,
        variant: state.success ? 'default' : 'destructive',
      });
       if (state.success && state.redirectUrl) {
        router.push(state.redirectUrl);
      }
    }
  }, [state, toast, router]);

  return (
    <form action={formAction} className="space-y-4">
      <div>
        <Label htmlFor="email" className="font-body">Email</Label>
        <Input type="email" id="email" name="email" placeholder="m@example.com" required className="mt-1 font-body" />
      </div>
      <div>
        <Label htmlFor="password" className="font-body">Password</Label>
        <Input type="password" id="password" name="password" placeholder="••••••••" required className="mt-1 font-body" />
      </div>
       <div>
        <Label htmlFor="confirmPassword" className="font-body">Confirm Password</Label>
        <Input type="password" id="confirmPassword" name="confirmPassword" placeholder="••••••••" required className="mt-1 font-body" />
      </div>
      <SubmitButton />
    </form>
  );
}
